function parseRange(s) {
  const parts = s.split('-');
  if (parts.length === 1) {
    return [parseInt(parts[0], 10)];
  }
  const a = parseInt(parts[0], 10);
  const b = parseInt(parts[1], 10);
  const result = [];
  if (a <= b) {
    for (let i = a; i <= b; i++) {
      result.push(i);
    }
  } else {
    for (let i = a; i >= b; i--) {
      result.push(i);
    }
  }
  return result;
}
